const htmlContent = $input.first().json.data;

const memeSet = new Set();

// 1. Extract from main gallery feed: .item[data-title]
const itemRegex = /<[^>]*class=["'][^"']*\bitem\b[^"']*["'][^>]*data-title=["']([^"']+)["']/gi;
let match;
while ((match = itemRegex.exec(htmlContent)) !== null) {
    const title = match[1].trim();
    if (title && !/^\d|days ago|ago|©/.test(title)) memeSet.add(title);
}

// 2. Extract from cards with alt text: <img ... alt="Meme Title">
const imgAltRegex = /<img[^>]+alt=["']([^"']+)["']/gi;
while ((match = imgAltRegex.exec(htmlContent)) !== null) {
    const title = match[1].trim();
    if (title && !/^\d|days ago|ago|©/.test(title)) memeSet.add(title);
}

// 3. Extract from "Popular Searches" links
const popularRegex = /<a[^>]*href=["'][^"']+["'][^>]*>([^<]+)<\/a>/gi;
while ((match = popularRegex.exec(htmlContent)) !== null) {
    const text = match[1].trim();
    if (text && !/Meme Encyclopedia|Submit|Guides|Popular|©/.test(text)) memeSet.add(text);
}

// Convert to array
let memes = Array.from(memeSet);

// **Keep only items before the first "KYM"**
const indexOfKYM = memes.findIndex(m => m.includes('KYM'));
if (indexOfKYM >= 0) {
    memes = memes.slice(0, indexOfKYM);
}

// Output for n8n
return [{ json: { memes } }];

// 1) Get the raw string
const raw = $input.first().json.output;

// 2) Parse JSON string
const data = JSON.parse(raw);

// 3) Extract fields
const title = data.title;
const introduction = data.introduction;
const sections = data.sections;

// 4) Build HTML body
let body = `<p>${introduction}</p>`;

for (const s of sections) {
  body += `<h2>${s.heading}</h2>`;

  if (s.content) {
    for (const p of s.content) {
      body += `<p>${p}</p>`;
    }
  }

  if (s.list) {
    body += `<ul>`;
    for (const li of s.list) {
      body += `<li>${li}</li>`;
    }
    body += `</ul>`;
  }
}

// 5) Separate intro paragraph (HTML)
const intro_html = `<p>${introduction}</p>`;

return [
  {
    json: {
      title,
      body,
      intro_html
    }
  }
];

